import React, { useState, useEffect } from 'react';
import { View, StyleSheet, TextInput, TouchableOpacity, Text, Dimensions, FlatList, TouchableWithoutFeedback } from 'react-native';
import { useSelector } from 'react-redux';
import { RootState } from '../../features/store';
import { Mission } from '../../features/missionSlice';
import Map, { MapMarker } from '../../components/maps';
import * as Location from 'expo-location';
import { useNavigation } from '@react-navigation/native';
import { MainTabNavigationProp } from '../../types/navigation';
import generateMission from '../../services/missionGenerator';

const { width, height } = Dimensions.get('window');

interface CityMarker {
  coordinate: { latitude: number; longitude: number };
  title: string;
  description: string;
}

interface CitySuggestion {
  display_name: string;
  lat: string;
  lon: string;
  address?: { city?: string; town?: string; village?: string };
}

const MapScreen = () => {
  const navigation = useNavigation<MainTabNavigationProp>();
  const { user } = useSelector((state: RootState) => state.auth);
  const [region, setRegion] = useState({
    latitude: 40.416775,
    longitude: -3.70379,
    latitudeDelta: 0.0922,
    longitudeDelta: 0.0421,
  });
  const [searchCity, setSearchCity] = useState('');
  const [duration, setDuration] = useState('');
  const [missionCount, setMissionCount] = useState('');
  const [missions, setMissions] = useState<Mission[]>([]);
  const [cityMarker, setCityMarker] = useState<CityMarker | null>(null);
  const [suggestions, setSuggestions] = useState<CitySuggestion[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    (async () => {
      let { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        setErrorMsg('Se requiere permiso para acceder a la ubicación');
        return;
      }
      let location = await Location.getCurrentPositionAsync({});
      setRegion({
        latitude: location.coords.latitude,
        longitude: location.coords.longitude,
        latitudeDelta: 0.0922,
        longitudeDelta: 0.0421,
      });
    })();
  }, []);

  const fetchCitySuggestions = async (query: string) => {
    if (query.length < 3) {
      setSuggestions([]);
      return;
    }
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${query}`);
      const data: CitySuggestion[] = await response.json();
      setSuggestions(data);
      setShowSuggestions(true);
    } catch (error) {
      console.error('Error fetching city suggestions:', error);
    }
  };

  const handleCitySelect = (city: CitySuggestion) => {
    setSearchCity(city.display_name);
    setCityMarker({
      coordinate: { latitude: parseFloat(city.lat), longitude: parseFloat(city.lon) },
      title: city.address?.city || city.address?.town || city.address?.village || 'Ciudad',
      description: city.display_name,
    });
    setRegion({
      latitude: parseFloat(city.lat),
      longitude: parseFloat(city.lon),
      latitudeDelta: 0.0922,
      longitudeDelta: 0.0421,
    });
    setShowSuggestions(false);
  };

  const handleSearch = async () => {
    if (!user?.id) {
      setErrorMsg('Debes iniciar sesión para generar misiones');
      return;
    }
    const durationNum = parseInt(duration);
    const missionCountNum = parseInt(missionCount);
    if (!searchCity || !durationNum || !missionCountNum) {
      setErrorMsg('Por favor, completa todos los campos');
      return;
    }
    try {
      setIsLoading(true);
      setErrorMsg(null);
      const result = await generateMission(searchCity, durationNum, missionCountNum, user.id);
      if (!result.journeyId) throw new Error('No se recibió el ID del journey');
      
      navigation.navigate('Missions');
    } catch (error) {
      setErrorMsg('Error al generar las misiones. Inténtalo de nuevo.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleMapPress = async (event: any) => {
    const { coordinate } = event.nativeEvent;
    setCityMarker({
      coordinate,
      title: 'Cargando...',
      description: 'Obteniendo nombre de la ciudad...',
    });
    setRegion({
      latitude: coordinate.latitude,
      longitude: coordinate.longitude,
      latitudeDelta: 0.0922,
      longitudeDelta: 0.0421,
    });

    // Geocodificación inversa para obtener el nombre de la ciudad
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${coordinate.latitude}&lon=${coordinate.longitude}`);
      const data = await response.json();
      const cityName = data.address.city || data.address.town || data.address.village || 'Ciudad desconocida';
      setCityMarker((prev) => ({
        ...prev!,
        title: cityName,
        description: `Ubicación: ${cityName}`,
      }));
    } catch (error) {
      console.error('Error obteniendo el nombre de la ciudad:', error);
      setCityMarker((prev) => ({
        ...prev!,
        title: 'Error',
        description: 'No se pudo obtener el nombre de la ciudad.',
      }));
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.searchContainer}>
        <TextInput 
          style={styles.input} 
          placeholder="Buscar ciudad" 
          value={searchCity} 
          onChangeText={(text) => {
            setSearchCity(text);
            fetchCitySuggestions(text);
          }}
        />
        <TextInput style={styles.input} placeholder="Duración (días)" value={duration} onChangeText={setDuration} keyboardType="numeric" />
        <TextInput style={styles.input} placeholder="Número de misiones" value={missionCount} onChangeText={setMissionCount} keyboardType="numeric" />
        <TouchableOpacity style={[styles.button, isLoading && styles.buttonDisabled]} onPress={handleSearch} disabled={isLoading}>
          <Text style={styles.buttonText}>{isLoading ? 'Generando...' : 'Buscar Aventuras'}</Text>
        </TouchableOpacity>
        {errorMsg ? <Text style={styles.errorText}>{errorMsg}</Text> : null}
      </View>
      <Map style={styles.map} region={region} onPress={handleMapPress}>
        {cityMarker && <MapMarker coordinate={cityMarker.coordinate} title={cityMarker.title} description={cityMarker.description} />}
      </Map>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1 },
  map: { width: width, height: height * 0.7 },
  searchContainer: { padding: 15, backgroundColor: 'white', borderRadius: 10 },
  input: { height: 40, borderColor: '#ddd', borderWidth: 1, borderRadius: 5, marginBottom: 10, paddingHorizontal: 10 },
  suggestionItem: { padding: 10, borderBottomWidth: 1, borderBottomColor: '#ddd' },
  button: { backgroundColor: '#4CAF50', padding: 15, borderRadius: 5, alignItems: 'center' },
  buttonDisabled: { backgroundColor: '#cccccc' },
  buttonText: { color: 'white', fontWeight: 'bold' },
  errorText: { color: 'red', marginTop: 10, textAlign: 'center' },
});

export default MapScreen;
